// First define the showMessage function at the top
function showMessage(message, isSuccess = false) {
    const messageBox = document.getElementById('customMessageBox');
    if (!messageBox) return;
    
    messageBox.textContent = message;
    messageBox.style.display = 'block';
    messageBox.style.backgroundColor = isSuccess ? '#4CAF50' : '#ff4444';
    
    setTimeout(() => {
        messageBox.style.display = 'none';
    }, 5000);
}

document.addEventListener('DOMContentLoaded', function() {
    const registerForm = document.getElementById('registerForm');
    
    if (registerForm) {
        registerForm.addEventListener('submit', async function(e) {
            e.preventDefault();
            
            // Clear previous error highlights
            document.querySelectorAll('.input').forEach(input => {
                input.classList.remove('input-error');
            });
            
            try {
                const formData = new FormData(registerForm);
                const response = await fetch(registerForm.action, {
                    method: 'POST',
                    body: formData,
                    headers: {
                        'Accept': 'application/json'
                    }
                });

                // Handle non-OK responses
                if (!response.ok) {
                    try {
                        const errorData = await response.json();
                        throw new Error(errorData.message || 'Registration failed');
                    } catch {
                        throw new Error('Server error occurred');
                    }
                }

                const data = await response.json();
                
                if (data.success) {
                    window.location.href = data.redirect;
                } else {
                    showMessage(data.message, false);
                    
                    // Highlight problematic fields
                    if (data.error_type === 'username_exists') {
                        document.querySelector('input[name="username"]').classList.add('input-error');
                    } else if (data.error_type === 'email_exists') {
                        document.querySelector('input[name="email_address"]').classList.add('input-error');
                    } else if (data.error_type === 'password_mismatch') {
                        document.querySelectorAll('input[name="password"], input[name="confirm_password"]').forEach(input => {
                            input.classList.add('input-error');
                        });
                    }
                }
            } catch (error) {
                console.error('Registration error:', error);
                showMessage(error.message || 'An error occurred. Please try again.', false);
            }
        });
        
        // Clear error highlights when user starts typing
        document.querySelectorAll('.input').forEach(input => {
            input.addEventListener('input', function() {
                this.classList.remove('input-error');
            });
        });
    }
});